&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Team of the Tournament&lt;/strong&gt;&lt;/u&gt; is an honorary selection recognizing outstanding individual performances throughout the competition.&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Selection Criteria&lt;/strong&gt;&lt;/u&gt; generally includes runs scored, wickets taken, consistency, and match-winning impact.&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;All-Round Contribution&lt;/strong&gt;&lt;/u&gt; refers to a player&amp;rsquo;s ability to influence matches through batting, bowling, or fielding.&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;ICC Under-19 World Cup&lt;/strong&gt;&lt;/u&gt; serves as a talent pipeline for future international cricketers.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Tropical Deciduous Forests&amp;quot;.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Tropical Deciduous Forest is also referred&amp;nbsp;to as a&amp;nbsp;&lt;strong&gt;&amp;quot; Monsoon Forest&amp;quot;.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Tropical Deciduous forests&amp;nbsp;are found in the belt along the&lt;strong&gt; equator between the tropics of Cancer and Capricorn &lt;/strong&gt;as well as in the humid subtropics&lt;/li&gt;
	&lt;li&gt;Tropical Deciduous Forests are home to trees with &lt;strong&gt;broad leaves which shed &lt;/strong&gt;in one season of the year.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;The range of the rainfall in&amp;nbsp;this forest is &lt;strong&gt;70 - 200cms.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;There are &lt;strong&gt;two types of deciduous forest&lt;/strong&gt; namely -&lt;/li&gt;
&lt;/ul&gt;

&lt;ol style=&quot;margin-left: 40px;&quot;&gt;
	&lt;li&gt;Moist Deciduous Forest&lt;/li&gt;
	&lt;li&gt;Dry Deciduous Forest.&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Some of the &lt;strong&gt;major states&lt;/strong&gt; in which these types of forests are found are -&lt;/li&gt;
&lt;/ul&gt;

&lt;ol style=&quot;margin-left: 40px;&quot;&gt;
	&lt;li&gt;Madhya Pradesh&lt;/li&gt;
	&lt;li&gt;Uttar Pradesh&lt;/li&gt;
	&lt;li&gt;Chattisgarh&lt;/li&gt;
	&lt;li&gt;Odisha&lt;/li&gt;
	&lt;li&gt;Some parts of Maharashtra&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;The Correct Answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Agnishodh&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Army, IIT Madras Launch &amp;#39;Agnishodh&amp;#39; to Boost Defence Innovation.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;278&quot; data-start=&quot;169&quot;&gt;
	&lt;p data-end=&quot;278&quot; data-start=&quot;171&quot;&gt;&lt;strong data-end=&quot;186&quot; data-start=&quot;171&quot;&gt;Indian Army&lt;/strong&gt; and &lt;strong data-end=&quot;205&quot; data-start=&quot;191&quot;&gt;IIT Madras&lt;/strong&gt; have set up &lt;strong data-end=&quot;233&quot; data-start=&quot;218&quot;&gt;&amp;lsquo;Agnishodh&amp;rsquo;&lt;/strong&gt;, the &lt;strong data-end=&quot;275&quot; data-start=&quot;239&quot;&gt;Indian Army Research Cell (IARC)&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;384&quot; data-start=&quot;279&quot;&gt;
	&lt;p data-end=&quot;384&quot; data-start=&quot;281&quot;&gt;Located on the &lt;strong data-end=&quot;317&quot; data-start=&quot;296&quot;&gt;IIT Madras campus&lt;/strong&gt;, part of the Army&amp;rsquo;s &lt;strong data-end=&quot;372&quot; data-start=&quot;338&quot;&gt;Five Pillars of Transformation&lt;/strong&gt; strategy.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;481&quot; data-start=&quot;385&quot;&gt;
	&lt;p data-end=&quot;481&quot; data-start=&quot;387&quot;&gt;&lt;strong data-end=&quot;400&quot; data-start=&quot;387&quot;&gt;Agnishodh&lt;/strong&gt; focuses on &lt;strong data-end=&quot;453&quot; data-start=&quot;412&quot;&gt;Modernisation and Technology Infusion&lt;/strong&gt;, one of the five pillars.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;624&quot; data-start=&quot;482&quot;&gt;
	&lt;p data-end=&quot;624&quot; data-start=&quot;484&quot;&gt;It aims to &lt;strong data-end=&quot;551&quot; data-start=&quot;495&quot;&gt;convert lab innovations into deployable defence tech&lt;/strong&gt; through collaboration with &lt;strong data-end=&quot;607&quot; data-start=&quot;579&quot;&gt;IIT Madras Research Park&lt;/strong&gt; and &lt;strong data-end=&quot;621&quot; data-start=&quot;612&quot;&gt;AMTDC&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;766&quot; data-start=&quot;625&quot;&gt;
	&lt;p data-end=&quot;766&quot; data-start=&quot;627&quot;&gt;Areas of research include &lt;strong data-end=&quot;679&quot; data-start=&quot;653&quot;&gt;additive manufacturing&lt;/strong&gt;, &lt;strong data-end=&quot;698&quot; data-start=&quot;681&quot;&gt;cybersecurity&lt;/strong&gt;, &lt;strong data-end=&quot;721&quot; data-start=&quot;700&quot;&gt;quantum computing&lt;/strong&gt;, &lt;strong data-end=&quot;749&quot; data-start=&quot;723&quot;&gt;wireless communication&lt;/strong&gt;, and &lt;strong data-end=&quot;763&quot; data-start=&quot;755&quot;&gt;UAVs&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;862&quot; data-start=&quot;767&quot;&gt;
	&lt;p data-end=&quot;862&quot; data-start=&quot;769&quot;&gt;The initiative will also &lt;strong data-end=&quot;824&quot; data-start=&quot;794&quot;&gt;upskill military personnel&lt;/strong&gt; in &lt;strong data-end=&quot;859&quot; data-start=&quot;828&quot;&gt;emerging technology domains&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;983&quot; data-start=&quot;863&quot;&gt;
	&lt;p data-end=&quot;983&quot; data-start=&quot;865&quot;&gt;This effort strengthens the link between the &lt;strong data-end=&quot;935&quot; data-start=&quot;910&quot;&gt;military and academia&lt;/strong&gt; to accelerate &lt;strong data-end=&quot;982&quot; data-start=&quot;950&quot;&gt;indigenous defence solutions&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;wildlife protection.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;br /&gt;
&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Amrita Devi Bishnoi Award&lt;/span&gt;&amp;nbsp;is given to the people for their courage and dedication to&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;protecting wildlife.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;In 1731&lt;/span&gt;, the king of Jodhpur in Rajasthan asked one of his ministers to arrange wood for constructing a new palace.&lt;/li&gt;
	&lt;li&gt;The minister and workers went to a forest near a village, inhabited by Bishnois, to cut down trees.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;The Bishnoi community&lt;/span&gt;&amp;nbsp;is known for its peaceful co-existence with nature.&lt;/li&gt;
	&lt;li&gt;The effort to cut down trees by the kings&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;was thwarted by the Bishnois.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;A Bishnoi woman Amrita Devi&amp;nbsp;&lt;/span&gt;showed exemplary courage by hugging a tree and daring the king&amp;rsquo;s men to cut her first before cutting the tree.&lt;/li&gt;
	&lt;li&gt;The tree mattered much more to her than her own life.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Bullets and Numbering&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Bullets and Numbering&amp;nbsp;feature of MS Word help to create a list in&amp;nbsp;a document&lt;/strong&gt;&lt;/u&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Bullets and Numbering are used to create a list in documents in MS word.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;To create a list in MS Word:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Select the text required&amp;nbsp;to format as a list.&lt;/li&gt;
		&lt;li&gt;Click on the Bullets or Numbering drop-down option on the Home tab.&lt;/li&gt;
		&lt;li&gt;Select the bullet or numbering style required, and it will appear in the document.&lt;/li&gt;
		&lt;li&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/09/bulle.png&quot; /&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Word wrap &lt;/strong&gt;is&amp;nbsp;a word processing feature that&lt;strong&gt; automatically transfers a word that has no&amp;nbsp;insufficient space&lt;/strong&gt; from the end of one line of text to the beginning of the next.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Scaling &lt;/strong&gt;in MS Word is another text effect to &lt;strong&gt;make the text larger or smaller.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;WordArt &lt;/strong&gt;is used to create &lt;strong&gt;decorative effects to the&amp;nbsp;text styles&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&lt;strong&gt;&amp;nbsp;&lt;u&gt;Third five-year plan&lt;/u&gt;&lt;/strong&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Though the planned economic development in India began in 1951 with the inception of the First Five Year Plan, theoretical efforts had begun much earlier, even prior to the independence.&lt;/li&gt;
	&lt;li&gt;Setting up of &lt;strong&gt;National Planning Committee by Indian National Congress in 1938&lt;/strong&gt;, &lt;strong&gt;The Bombay Plan&lt;/strong&gt; &amp;amp; &lt;strong&gt;Gandhian Plan in 1944&lt;/strong&gt;, &lt;strong&gt;Peoples Plan in 1945&lt;/strong&gt; (by post-war reconstruction Committee of Indian Trade Union), &lt;strong&gt;Sarvodaya Plan in 1950&lt;/strong&gt; by &lt;strong&gt;Jaiprakash Narayan&lt;/strong&gt; stepped in this direction.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Five-Year Plans (FYPs)&lt;/strong&gt;&amp;nbsp;:
	&lt;ul&gt;
		&lt;li&gt;Five-Year Plans&amp;nbsp;&lt;strong&gt;centralized&lt;/strong&gt; and &lt;strong&gt;integrated national economic programs&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Joseph Stalin&lt;/strong&gt; &lt;strong&gt;implemented the first FYP in the Soviet Union&lt;/strong&gt; in the late 1920s.&lt;/li&gt;
		&lt;li&gt;Most communist states and several capitalist countries subsequently have adopted them.&lt;/li&gt;
		&lt;li&gt;China and India both continue to use FYPs.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;Plan&lt;/td&gt;
			&lt;td&gt;&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;First Plan (1951 - 56)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Target Growth =&amp;nbsp;2.1%&lt;/li&gt;
				&lt;li&gt;Actual Growth = 3.6%&amp;nbsp;&lt;/li&gt;
				&lt;li&gt;Harrod-Domar Model&lt;/li&gt;
				&lt;li&gt;Focussed on agriculture&lt;/li&gt;
				&lt;li&gt;Successful plan&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;Second Plan (1956 - 61)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Target Growth = 4.5%&lt;/li&gt;
				&lt;li&gt;Actual Growth =&amp;nbsp;4.3%&lt;/li&gt;
				&lt;li&gt;Mahalanobis Plan&lt;/li&gt;
				&lt;li&gt;Rapid industrialization- heavy &amp;amp; basic&lt;br /&gt;
				industries&lt;/li&gt;
				&lt;li&gt;the Socialistic pattern of society&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;Third Plan (1961 - 66)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Target Growth =&amp;nbsp;5.6%&lt;/li&gt;
				&lt;li&gt;Actual Growth = 2.8%&lt;/li&gt;
				&lt;li&gt;To make India a &amp;#39;self-reliant&amp;#39; and&lt;br /&gt;
				self-generating economy.&amp;nbsp;&lt;/li&gt;
				&lt;li&gt;Failure&amp;nbsp;&lt;/li&gt;
				&lt;li&gt;Shifted from development to defense &amp;amp;&lt;br /&gt;
				development&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;Sixth Plan (1980 - 85)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Target Growth = 5.2%&lt;/li&gt;
				&lt;li&gt;Actual Growth = 5.7%&lt;/li&gt;
				&lt;li&gt;Increase in national income, modernization of&lt;br /&gt;
				technology, ensuring a continuous decrease in poverty and unemployment.&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&amp;nbsp;&lt;/p&gt;

			&lt;p&gt;Seventh Plan (1985 - 90)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Target Growth = 5.0%&lt;/li&gt;
				&lt;li&gt;Actual Growth = 6.0%&lt;/li&gt;
				&lt;li&gt;Food, work &amp;amp; productivity&lt;/li&gt;
				&lt;li&gt;Very successful&lt;/li&gt;
			&lt;/ul&gt;
